/* Prize 随机宏, 按照概率随机并返回选项 */
(()=>{const draw=options=>{const totalProb=Object.values(options).reduce(((acc,prob)=>acc+prob),0);if(Math.abs(totalProb-1)>1e-8){throw new Error("Total probability does not sum to 1")}const cumProbs=[];let acc=0;for(const prob of Object.values(options)){acc+=prob;cumProbs.push(acc)}const randVal=Math.random();const idx=cumProbs.findIndex((prob=>prob>randVal));const result=Object.keys(options)[idx];return result};Macro.add("prize",{tags:null,handler(){if(this.args.length===0){return this.error("No provide options")}const options=this.args[0];if(typeof options!=="object"){return this.error("Please provide object")}const shadowStore={};const varName="result";if(Object.hasOwn(State.temporary,varName)){shadowStore[`_${varName}`]=State.temporary[varName]}State.temporary[varName]=draw(options);this.addShadow(`_${varName}`);if(Object.hasOwn(State.variables,varName)){shadowStore[`$${varName}`]=State.variables[varName]}State.variables[varName]=State.temporary[varName];this.addShadow(`$${varName}`);try{new Wikifier(this.output,this.payload[0].contents)}finally{if(Object.hasOwn(shadowStore,`_${varName}`)){State.temporary[varName]=shadowStore[`_${varName}`]}else{delete State.temporary[varName]}if(Object.hasOwn(shadowStore,`$${varName}`)){State.variables[varName]=shadowStore[`$${varName}`]}else{delete State.variables[varName]}}}})})();
/* Prize 随机宏*/